const fileBase64 = ''

const metadata = {
  "files": [
    { "filename": "/wechat_qrcode/detect.prototxt", "start": 0, "end": 42656, "audio": 0 },
    { "filename": "/wechat_qrcode/sr.caffemodel", "start": 42656, "end": 66585, "audio": 0 },
    { "filename": "/wechat_qrcode/sr.prototxt", "start": 66585, "end": 72569, "audio": 0 },
    { "filename": "/wechat_qrcode/detect.caffemodel", "start": 72569, "end": 1037999, "audio": 0 }
  ],
  "remote_package_size": 1037999,
  "package_uuid": "190540bd-18cf-4576-9232-dd354a4a06e0"
}

const loadWechatFile = (Module: any) => {
  const data = Buffer.from(fileBase64, 'base64')

  Module['FS_createPath']("/", "wechat_qrcode", true, true);
  Module['addRunDependency']('datafile_build_wasm/bin/wechat_qrcode_files.data');
  metadata.files.forEach((file) => {
    const byteArray = data.subarray(file.start, file.end)
    Module['FS_createDataFile'](file.filename, null, byteArray, true, true, true )
  })
  Module['removeRunDependency']('datafile_build_wasm/bin/wechat_qrcode_files.data');
}

export const initWechatFile = (Module: any) => {
  if (Module['calledRun']) {
    loadWechatFile(Module);
  } else {
    if (!Module['preRun']) {
      Module['preRun'] = [];
    }
    Module["preRun"].push(loadWechatFile); // FS is not initialized yet, wait for it
  }
}